sql:
SELECT tag_name
FROM image_tags
WHERE LENGTH(tag_description) = (
  SELECT MAX(LENGTH(tag_description))
  FROM image_tags
);

SELECT MAX(tag_count) AS max_tags
FROM (
  SELECT COUNT(*) AS tag_count
  FROM image_tags
  GROUP BY image_id
);

SELECT MAX(tag_count) AS highest_usage
FROM (
  SELECT COUNT(tag_name) AS tag_count
  FROM image_tags
  GROUP BY tag_name
);

SELECT DISTINCT tag_name
FROM image_tags
ORDER BY tag_name;

SELECT image_tag_id, tag_name
FROM image_tags
WHERE image_tag_id = (SELECT MAX(image_tag_id) FROM image_tags);

external_knowledge:
- "Hierarchical structure" refers to the nested levels of tag descriptions;
- "Frequency" is the count of occurrences of each tag name;
- "Total number of tags" is the count of all unique `image_tag_id` in the `image_tags` table.

sql:
SELECT MAX(unique_tag_count) AS max_unique_tags_count
FROM (
  SELECT COUNT(DISTINCT tag_name) AS unique_tag_count
  FROM image_tags
  GROUP BY image_id
);

external_knowledge:
- "decorated" refers to the image having the highest number of tags;
- "gallery of digital art" metaphorically represents the database of images;
- "tags it has accumulated" refers to the `image_tag_id` entries associated with each `image_id`.

- "Blooming flowers" refers to the most common image tags;
- "Sharing their beauty" refers to the co-occurrence of tags on the same image;
- "Less common flowers" refers to tags that are not among the top 10 most common tags.

sql:
SELECT MAX(tag_count) AS max_tag_count
FROM (
  SELECT image_id, COUNT(image_tag_id) AS tag_count
  FROM image_tags
  GROUP BY image_id
);

